mapper.select:
SELECT TIME as time, PARTITION_NAME as partitionName, UTILIZATION as utilization, USED as used
FROM TBL_HOST_PARTITION_DETAIL dpd  WHERE dpd.HOST_ID = ${hostId} AND TIME BETWEEN ${startTime} AND ${endTime}
ORDER BY TIME ASC

SELECT TIME as time, hpd.HOST_ID as hostId, PARTITION_NAME as partitionName, UTILIZATION as utilization, SIZE as size, MOUNTED_DIR as mountedDir, host.name as hostName,host.status as hostStatus FROM TBL_HOST_PARTITION_DETAIL hpd LEFT JOIN ${@com.h3c.h3cloud.performance.monitor.service.mapper.base.clickhouseMapperConstant@TBL_HOST} host ON hpd.HOST_ID = host.id WHERE host.id is NOT NULL AND hpd.PARTITION_TYPE !=#{partitionType} AND TIME = (SELECT MAX(TIME) FROM TBL_HOST_PARTITION_DETAIL)
AND hpd.OP_GROUP_CODE like #{operatorGroupCode}
ORDER BY HOST_ID

SELECT PARTITION_NAME as partitionName, UTILIZATION as utilization, SIZE as size, MOUNTED_DIR as mountedDir, PARTITION_TYPE as partitionType, USED as used
FROM TBL_HOST_PARTITION_DETAIL hpd  WHERE hpd.HOST_ID=${hostId}
AND TIME = (SELECT MAX(TIME) FROM TBL_HOST_PARTITION_DETAIL)
